package com.example.api;

import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.boot.SpringApplication;
import org.springframework.boot.autoconfigure.SpringBootApplication;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

import java.util.Collections;
import java.util.Map;

@SpringBootApplication
@RestController
@RequestMapping("/api")
public class Application {
    private static final Logger logger = LoggerFactory.getLogger(Application.class);

    public static void main(String[] args) {
        logger.info("Starting Application");
        SpringApplication.run(Application.class, args);
        logger.info("Application started successfully");
    }

    @GetMapping("/health")
    public ResponseEntity<Map<String, String>> healthCheck() {
        logger.info("Health check endpoint called");
        try {
            logger.debug("Health check processing");
            return ResponseEntity.ok(Collections.singletonMap("status", "healthy"));
        } catch (Exception e) {
            logger.error("Health check failed", e);
            return ResponseEntity.status(500).build();
        }
    }

    @GetMapping("/users/{id}")
    public ResponseEntity<Map<String, Object>> getUser(@PathVariable Long id) {
        logger.info("Retrieving user with ID: {}", id);
        try {
            if (id == null || id <= 0) {
                logger.warn("Invalid user ID provided: {}", id);
                return ResponseEntity.badRequest().build();
            }
            logger.debug("User retrieval successful for ID: {}", id);
            return ResponseEntity.ok(Collections.singletonMap("id", id));
        } catch (Exception e) {
            logger.error("Failed to retrieve user with ID: {}", id, e);
            return ResponseEntity.status(500).build();
        }
    }

    @PostMapping("/users")
    public ResponseEntity<Map<String, Object>> createUser(@RequestBody Map<String, Object> user) {
        logger.info("Creating new user with data: {}", user);
        try {
            if (user == null || user.isEmpty()) {
                logger.warn("User creation failed - empty request body");
                return ResponseEntity.badRequest().build();
            }
            logger.debug("User creation successful for user data: {}", user);
            return ResponseEntity.ok(Collections.singletonMap("status", "created"));
        } catch (Exception e) {
            logger.error("Failed to create user with data: {}", user, e);
            return ResponseEntity.status(500).build();
        }
    }
}